function searchA2dMatrix(data) {
    const matrix = data[0];
    const target = data[1];
    if (matrix.length === 0 || matrix[0].length === 0) return false;
    let rows = matrix.length;
    let cols = matrix[0].length;
    let row = 0;
    let col = cols - 1;
    while (row < rows && col >= 0) {
        if (matrix[row][col] === target) {
            return true;
        }
        else if (matrix[row][col] > target) {
            col--;
        }
        else {
            row++;
        }
    }
    return false;
}

