#include <vector>
#include <string>
using namespace std;
class Solution {
    public:
    bool searchA2dMatrix(vector<vector<int>>& data, int target) {
        if (data.empty() || data[0].empty()) return false;
        int rows = data.size();
        int cols = data[0].size();
        int left = 0, right = rows * cols - 1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            int midValue = data[mid / cols][mid % cols];
            if (midValue == target) {
                return true;
            }
            else if (midValue < target) {
                left = mid + 1;
            }
            else {
                right = mid - 1;
            }
        }
        return false;
    }
}
